import React from 'react';

export default function AutomataSVG({ automata, type, highlightPath }) {
  if (!automata) {
    return (
      <div style={{ color: '#94a3b8', padding: '20px' }}>
        No automata generated yet
      </div>
    );
  }

  return (
    <div style={{ color: 'white', padding: '20px' }}>
      <h4>{type}</h4>

      <div>
        States: {automata.states?.join(', ')}
      </div>

      <div>
        Start: {automata.start}
      </div>

      <div>
        Accept:
        {
          Array.isArray(automata.accepts)
            ? automata.accepts.join(', ')
            : automata.accept
        }
      </div>

      <pre style={{
        marginTop: '15px',
        background: '#0f172a',
        padding: '10px',
        borderRadius: '8px',
        overflow: 'auto'
      }}>
        {JSON.stringify(automata.transitions, null, 2)}
      </pre>
    </div>
  );
}
